---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  badge?: {
    label: string
    href: string
  }
  buttons: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  image: {
    src: ImageMetadata
    alt: string
  }
}

const {
  class: className,
  title,
  description,
  badge,
  buttons,
  image,
} = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="items-center gap-8 text-center">
    {
      badge && (
        <Badge as="a" href={badge.href} variant="secondary">
          {badge.label}
        </Badge>
      )
    }
    <h1
      class="text-foreground max-w-4xl text-4xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-5xl lg:text-6xl"
    >
      {title}
    </h1>
    <p
      class="text-muted-foreground max-w-2xl text-lg leading-relaxed text-balance"
    >
      {description}
    </p>
    <div class="flex flex-wrap justify-center gap-3">
      {
        buttons.map(({ href, label, ...button }, index) => (
          <Button
            as="a"
            href={href}
            size="lg"
            variant={button.variant ?? (index === 0 ? "default" : "secondary")}
            {...button}
          >
            {label}
          </Button>
        ))
      }
    </div>
  </SectionContainer>
  <SectionContainer>
    <Image
      src={image.src}
      alt={image.alt}
      class="aspect-video w-full rounded-xl border object-cover"
      widths={[640, 960, 1280, 1536]}
      sizes="(min-width: 80rem) 80rem, 100vw"
      loading="eager"
    />
  </SectionContainer>
</Section>
